var e=[{id:`L3_1`,type:`dialog`,speaker:`BOX_NPC_GAMECIRCLE_NULL`,text:{KOREA:`이게 라인 디펜스?`,JPN:`これがラインディフェンス？`,ENG:`Is this what line defense games are like...?`,TWN:`這就是防守防線？`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:{char_id:`BOX_NPC_GAMECIRCLE_NULL`,face:`UNIT_IDLE`}}}},{id:`L5_1`,type:`dialog`,speaker:`STAR_GAMECIRCLE_NULL_NULL`,text:{KOREA:`헤헷, 어때? 생각보다 할 만하제? 니 마음에 쏙 들제?`,JPN:`へへっ、どう？　思ったよりええやろ？　気に入ったんちゃう？`,ENG:`Heh, so? Whaddaya say? Ain’t so bad after all, right?`,TWN:`嘿嘿，怎麼樣？還不錯玩唄？你喜歡嗎？`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`BOX_NPC_GAMECIRCLE_NULL`,face:`UNIT_IDLE`}}}},{id:`L6_1`,type:`dialog`,speaker:`BOX_NPC_GAMECIRCLE_NULL`,text:{KOREA:`뭐…… 걱정했던 것보다는 나쁘지 않은 것 같은데요.`,JPN:`まあ……心配していたよりは悪くないですけど。`,ENG:`I guess... It’s not as bad as I thought it would be.`,TWN:`嗯……原本是有點擔心，但還可以啦。`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`BOX_NPC_GAMECIRCLE_NULL`,face:`UNIT_SERIOUS2`}}}},{id:`L7_1`,type:`dialog`,speaker:`STAR_GAMECIRCLE_NULL_NULL`,text:{KOREA:`헤헷, 그쟈? 그쟈? 내 자신 있다 아이가!`,JPN:`へへっ、やろ？　な？　自信あるねん！`,ENG:`Heh. Hear, hear! I told ya it’s good!`,TWN:`嘿嘿，是不是？這可是我的信心之作！`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`BOX_NPC_GAMECIRCLE_NULL`,face:`UNIT_SERIOUS2`}}}},{id:`L8_1`,type:`dialog`,speaker:`BOX_NPC_GAMECIRCLE_NULL`,text:{KOREA:`아, 아직 재밌다는 뜻은 아니에요! 조금 더 진행을……`,JPN:`ま、まだ面白いってことじゃないですよ！　もう少しやって……`,ENG:`I-I never said it was good! I still need to–`,TWN:`呃…我還沒覺得好玩啦！我再玩一下……`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`BOX_NPC_GAMECIRCLE_NULL`,face:`UNIT_SERIOUS2`}}}},{id:`L11_1`,type:`dialog`,speaker:`BOX_NPC_GAMECIRCLE_NULL`,text:{KOREA:`엇!?`,JPN:`あっ！？`,ENG:`Huh?!`,TWN:`嗯！？`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BOX_NPC_GAMECIRCLE_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`BOX_NPC_GAMECIRCLE_NULL`,text:{KOREA:`갑자기 적들이 좀 이상해진 것 같은데요?`,JPN:`急に敵の動きがおかしくなった気がするんですけど？`,ENG:`These enemies look a little strange.`,TWN:`敵人怎麼突然變得很奇怪？`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BOX_NPC_GAMECIRCLE_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`STAR_GAMECIRCLE_NULL_NULL`,text:{KOREA:`엥? 뭐라고? 뭐가 이상한데?`,JPN:`え？　何やて？　何がおかしい言うた？`,ENG:`Eh? What? How so?`,TWN:`啥？什麼？哪裡奇怪？`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`BOX_NPC_GAMECIRCLE_NULL`,text:{KOREA:`저기 봐요, 막 몸이 뒤틀리면서 움직이고 있잖아요! T자로 움직이는 애들도 있고!`,JPN:`ほら、体が歪んで動いてるじゃないですか！　T字に動くやつもありますし！`,ENG:`Look! they’re all crippled and jittering! Some of them are even moving in a T-pose!`,TWN:`你看，移動的時候姿勢很不自然！雙臂擺動時呈現T字形！`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BOX_NPC_GAMECIRCLE_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`STAR_GAMECIRCLE_NULL_NULL`,text:{KOREA:`에…… 에엥!?`,JPN:`え……ええっ！？`,ENG:`Eh... Ehhhhhh?!`,TWN:`啥……怎麼會這樣！？`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`STAR_GAMECIRCLE_NULL_NULL`,text:{KOREA:`다, 다인아! 일로 퍼뜩 와봐라! 점마들 저거 몬스터가 좀 이상한데?`,JPN:`た、タエ！　早くこっち来てや！　あれ見て、モンスターがちょっとおかしいんやけど？`,ENG:`D-Dain! Come here, quick! Them monsters look crazy as a bullbat!`,TWN:`妲…妲茵！你快過來看看！那邊的怪物好像怪怪的唄？`},stage:{bg:`BLACK`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`STAR_GAMECIRCLE_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};